declare @$none nvarchar(512), @vcDate smalldatetime
select @vcDate = ngay_ct from kkyc with(index(so_ct)) where so_ct = @so_ct and ngay_ct between @ngay_ct1 and @ngay_ct2
if @vcDate is null begin
  select @$none = case when @@language = 'v' then N'Không có yêu cầu kiểm kê theo điều kiện đang lọc.' else N'No data matching filter condition.' end
  select 'so_ct' as field, isnull(@$none, '') as message
end







declare @vcID varchar(33), @c varchar(33)
select @vcID = stt_rec from kkyc where so_ct = @so_ct
select @ngay_ct1 as ngay_tu, @ngay_ct2 as ngay_den, upper(@so_ct) as phieu_yc, @nh_theo as nh_theo
select @c = case @nh_theo when '0' then 'loai_vt' when '1' then 'nh_vt1' when '2' then 'nh_vt2' when '3' then 'nh_vt3' else '' end
exec rs_rptStocktakingReport @vcID, @ma_kho, @nh_vt, @nh_vt2, @nh_vt3, @c, @@language, @@userID, @@admin







      &OutlineEntry;
      /* <flatten type="Javascript"> */
function init$StocktakingReport$(f) {f.getItem('so_ct')._idle = 9;}
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  f._looking = f.getItem('so_ct')._controlBehavior;
  f._looking.add_loading(on$InventoryLookupFilter$Before$Loading);
}
function close$VoucherFilter$(f) {
  try {f._looking.remove_loading(on$InventoryLookupFilter$Before$Loading);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}
}
function on$Filter$ResponseComplete(f, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, x = f.getItemValue('nh_theo');
      g._t = x;
      g._alterTitle = [null, [['%d1', f.getItem('ngay_ct1').value, true], ['%d2', f.getItem('ngay_ct2').value, true], ['%s', f.getItemValue('so_ct').toUpperCase(), true]]];
      try {init$GridReport$(g);} catch (ex) {}
      break;
    default:
      break;
  }
}

function on$InventoryLookupFilter$Before$Loading(sender, e) {
  var f = sender._element.parentForm;
  if ((!f.validFields('ngay_ct1')) || (!f.validFields('ngay_ct2'))) e.type.cancelEvent = true;
  else {
    var g = f.grid, w = g.get_element().parentForm;
    var d1 = f.getItemValue('ngay_ct1'), d2 = f.getItemValue('ngay_ct2');
    a = [
      {Name: 'd1', Type: 'DateTime', Value: d1},
      {Name: 'd2', Type: 'DateTime', Value: d2}
    ];
    sender.set_memvars(a);
  }
}
